370	func (w *ExecuteBeadWorker) Run(ctx context.Context, rcfg config.ResolvedConfig, runtime ExecuteBeadLoopRuntime) (*ExecuteBeadLoopResult, error) {
371		if w.Store == nil {
372			return nil, fmt.Errorf("execute-bead loop: store is required")
373		}
374		if w.Executor == nil {
375			return nil, fmt.Errorf("execute-bead loop: executor is required")
376		}
377	
378		now := w.Now
379		if now == nil {
380			now = time.Now
381		}
382		assignee := rcfg.Assignee()
383		if assignee == "" {
384			assignee = "ddx"
385		}
386		noProgressCooldown := rcfg.NoProgressCooldown()
387		if noProgressCooldown <= 0 {
388			noProgressCooldown = 6 * time.Hour
389		}
390		maxNoChangesBeforeClose := rcfg.MaxNoChangesBeforeClose()
391		if maxNoChangesBeforeClose <= 0 {
392			maxNoChangesBeforeClose = 3
393		}
394		heartbeatInterval := rcfg.HeartbeatInterval()
395		if heartbeatInterval <= 0 {
396			heartbeatInterval = bead.HeartbeatInterval
397		}
398		harness := rcfg.Harness()
399		model := rcfg.Model()
400		profile := rcfg.Profile()
401	
402		result := &ExecuteBeadLoopResult{}
403		attempted := make(map[string]struct{})
404		// triagedWarned suppresses the one-time boot warning when ComplexityGate is
405		// nil. One warning per Run() invocation is enough; the bool resets on the
406		// next worker boot.
407		triagedWarned := false
408		// hookFailed tracks beads whose pre-claim hook failed on first presentation
409		// in this run. A bead in hookFailed but not attempted gets one retry: on the
410		// second hook failure it moves to attempted so nextCandidate will skip it and
411		// the loop can exit gracefully. This prevents infinite spinning when the hook
412		// always fails while still allowing transient hook failures to be retried.
413		hookFailed := make(map[string]struct{})
414	
415		emit := func(eventType string, data map[string]any) {
416			writeLoopEvent(runtime.EventSink, runtime.SessionID, eventType, data, now().UTC())
417		}
418	
419		emit("loop.start", map[string]any{
420			"worker_id":    runtime.WorkerID,
421			"project_root": runtime.ProjectRoot,
422			"harness":      harness,
423			"model":        model,
424			"session_id":   runtime.SessionID,
425			"assignee":     assignee,
426			"once":         runtime.Once,
427		})
428		// exitReason is populated as the loop exits to surface a structured reason
429		// in the loop.end event (ddx-dc157075 AC #4). Recognized values: "sigterm",
430		// "sigint", "fatal_config", "once_complete", "explicit_poll_zero". The
431		// "providers_exhausted" slot is reserved for ddx-aede917d (quota pause).
432		exitReason := ""
433		defer func() {
434			emit("loop.end", map[string]any{
435				"attempts":            result.Attempts,
436				"successes":           result.Successes,
437				"failures":            result.Failures,
438				"last_failure_status": result.LastFailureStatus,
439				"exit_reason":         exitReason,
440			})
441		}()
442	
443		for {
444			// Respect context cancellation between iterations. Without this check,
445			// a Stop() request (which cancels ctx) would only take effect during
446			// the idle poll sleep — the loop would happily claim the next ready
447			// bead as soon as the current Execute returned, ignoring the cancel.
448			if err := ctx.Err(); err != nil {
449				if exitReason == "" {
450					switch err {
451					case context.Canceled:
452						exitReason = "sigint"
453					case context.DeadlineExceeded:
454						exitReason = "sigterm"
455					default:
456						exitReason = "context_cancelled"
457					}
458				}
459				return result, err
460			}
461	
462			candidate, skips, ok, err := w.nextCandidate(attempted, runtime.LabelFilter)
463			if err != nil {
464				exitReason = "fatal_config"
465				return result, err
466			}
467			// Diagnostic: when nextCandidate selected a lower-priority bead while
468			// at least one higher-priority bead was skipped, emit a structured
469			// picker.priority_skip event naming each skipped bead and the reason
470			// (ddx-9d55601f AC #4). Without this surface, an operator who sees a
471			// worker claim a P2 while P0s sit in `ddx bead ready` cannot tell
472			// whether the picker has a bug, the P0s are filtered upstream, or a
473			// label filter is in play.
474			if ok {
475				emitPickerPrioritySkips(emit, candidate, skips)
476			}
477			if !ok {
478				if result.Attempts == 0 {
479					result.NoReadyWork = true
480					if diag, ok := w.Store.(readyDiagnoser); ok {
481						if breakdown, bErr := diag.ReadyExecutionBreakdown(); bErr == nil {
482							result.NoReadyWorkDetail = NoReadyWorkBreakdown{
483								SkippedEpics:       breakdown.SkippedEpics,
484								SkippedOnCooldown:  breakdown.SkippedOnCooldown,
485								SkippedNotEligible: breakdown.SkippedNotEligible,
486								SkippedSuperseded:  breakdown.SkippedSuperseded,
487								NextRetryAfter:     breakdown.NextRetryAfter,
488							}
489						}
490					}
491				}
492				if runtime.PollInterval <= 0 {
493					// Legacy "drain-and-exit" semantics: operator either passed
494					// --once (handled at end-of-iteration) or explicitly set
495					// --poll-interval=0. ddx-dc157075: with default --poll-interval
496					// flipped to 30s in CLI/server, this path now only fires for
497					// the explicit opt-out case.
498					if runtime.Once {
499						exitReason = "once_complete"
500					} else {
501						exitReason = "explicit_poll_zero"
502					}
503					return result, nil
504				}
505				// --once with poll-interval > 0: an empty queue still means there
506				// is no work to pick, and --once explicitly asked for at-most-one.
507				// Returning here preserves the operator-visible "drain and stop"
508				// semantics of --once even when the long-running default applies.
509				if runtime.Once {
510					exitReason = "once_complete"
511					return result, nil
512				}
513				// Long-running drain (poll-interval > 0): emit a transient
514				// "no_ready_work" event so server-managed workers can surface this
515				// as an idle substate (ddx-dc157075 AC #5) instead of treating it
516				// as terminal.
517				emit("loop.idle", map[string]any{
518					"reason":        "no_ready_work",
519					"poll_interval": runtime.PollInterval.String(),
520				})
521				// Surface the idle substate via the progress channel so server-side
522				// drainProgress can flip WorkerRecord.Substate to "idle" without
523				// reading the JSONL event log. Phase="loop.idle" is treated as a
524				// substate signal, not a per-bead attempt phase.
525				emitProgress(runtime.ProgressCh, ProgressEvent{
526					EventID:   "evt-" + randomProgressID(),
527					WorkerID:  runtime.WorkerID,
528					ProjectID: runtime.ProjectRoot,
529					Phase:     "loop.idle",
530					Heartbeat: true,
531					TS:        now().UTC(),
532					Message:   "no_ready_work",
533				})
534				// Reset per-Run attempted/hookFailed maps before sleeping
535				// (ddx-dc157075 AC #2). Without this reset, beads attempted earlier
536				// in this Run remain filtered out of nextCandidate forever, so the
537				// "attempted-once = exit" trap reasserts itself: a bead whose
538				// cooldown has expired since its last attempt would never be
539				// re-picked by the same long-running worker.
540				for k := range attempted {
541					delete(attempted, k)
542				}
543				for k := range hookFailed {
544					delete(hookFailed, k)
545				}
546				if err := sleepOrWake(ctx, runtime.PollInterval, runtime.WakeCh); err != nil {
547					if exitReason == "" {
548						switch err {
549						case context.Canceled:
550							exitReason = "sigint"
551						case context.DeadlineExceeded:
552							exitReason = "sigterm"
553						default:
554							exitReason = "context_cancelled"
555						}
556					}
557					return result, err
558				}
559				continue
560			}
561	
562			// Found a candidate: clear any "idle" substate set on the previous
563			// no-candidate iteration (ddx-dc157075 AC #5).
564			emitProgress(runtime.ProgressCh, ProgressEvent{
565				EventID:   "evt-" + randomProgressID(),
566				WorkerID:  runtime.WorkerID,
567				ProjectID: runtime.ProjectRoot,
568				BeadID:    candidate.ID,
569				Phase:     "loop.active",

570				Heartbeat: true,
571				TS:        now().UTC(),
572			})
573	
574			// Pre-claim hook: fetch origin + verify ancestry before claiming.
575			// On error the bead is skipped for this iteration; the loop
576			// continues (ctx is not cancelled). The bead is NOT added to
577			// attempted on the FIRST failure so a transient hook failure (e.g.
578			// diverged branch) allows a retry on the next iteration. On a
579			// SECOND failure for the same bead in the same run it is moved into
580			// attempted so nextCandidate will skip it, preventing an infinite
581			// loop when the hook always fails.
582			if runtime.PreClaimHook != nil {
583				if hookErr := runtime.PreClaimHook(ctx); hookErr != nil {
584					if runtime.Log != nil {
585						_, _ = fmt.Fprintf(runtime.Log, "pre-claim hook: %v (skipping %s)\n", hookErr, candidate.ID)
586					}
587					emit("preclaim.skipped", map[string]any{
588						"bead_id": candidate.ID,
589						"reason":  hookErr.Error(),
590					})
591					if _, alreadyFailed := hookFailed[candidate.ID]; alreadyFailed {
592						// Second failure in this run: stop retrying this bead.
593						attempted[candidate.ID] = struct{}{}
594					} else {
595						hookFailed[candidate.ID] = struct{}{}
596					}
597					continue
598				}
599			}
600	
601			attempted[candidate.ID] = struct{}{}
602	
603			// Routing preflight gate (FEAT-006 D3, ddx-98e6e9ef): consult the
604			// upstream typed-incompatibility surface BEFORE claiming. If the
605			// configured (harness, model) cannot serve the bead, exit the loop
606			// with a worker-level failure record — no claim, no executor
607			// invocation, no tier-attempt event burn.
608			if runtime.RoutePreflight != nil {
609				if rerr := runtime.RoutePreflight(ctx, harness, model); rerr != nil {
610					detail := fmt.Sprintf("routing preflight rejected (harness=%s model=%s): %s",
611						harness, model, rerr.Error())
612					if runtime.Log != nil {
613						_, _ = fmt.Fprintf(runtime.Log, "routing preflight: %s (skipping %s)\n",
614							detail, candidate.ID)
615					}
616					emit("preflight.rejected", map[string]any{
617						"bead_id": candidate.ID,
618						"harness": harness,
619						"model":   model,
620						"reason":  rerr.Error(),
621					})
622					report := ExecuteBeadReport{
623						BeadID:           candidate.ID,
624						Status:           ExecuteBeadStatusExecutionFailed,
625						Detail:           detail,
626						Harness:          harness,
627						Model:            model,
628						Disrupted:        true,
629						DisruptionReason: "preflight_rejected",
630					}
631					// ddx-5b3e57f4: a routing preflight rejection is an operator
632					// configuration issue (harness/model allow-list mismatch), not
633					// evidence the model could not make progress. Mark the report
634					// Disrupted and emit the diagnostic event so operators can see
635					// disruption rates without parking the bead in a no-progress
636					// cooldown.
637					emitDisruptionDetected(emit, w.Store, candidate.ID,
638						"preflight_rejected", detail, harness, model, assignee, now().UTC())
639					result.Attempts++
640					result.Failures++
641					result.LastFailureStatus = report.Status
642					result.Results = append(result.Results, report)
643					// ddx-dc157075 AC #3: do NOT abandon the rest of the queue on
644					// a single bead's preflight rejection. Continue to the next
645					// candidate. If --once was requested we still honour it.
646					if runtime.Once {
647						exitReason = "once_complete"
648						return result, nil
649					}
650					continue
651				}
652			}
653	
654			// Complexity triage gate (ddx-5bf4ee7e): pre-Claim decomposition check.
655			// When the gate is nil, decomposition responsibility shifts to the
656			// LLM-driven path inside execute-bead (ddx-b790449b AC5): the agent
657			// is prompted to recognize coarse beads, file children, and exit
658			// early. The pre-dispatch warning is intentionally suppressed —
659			// it is no longer accurate now that decomposition lives downstream.
660			if w.ComplexityGate == nil {
661				_ = triagedWarned // retained for future re-introduction of a typed gate
662			} else {
663				shouldClaim, triageErr := w.ComplexityGate(ctx, candidate)
664				if triageErr != nil {
665					if runtime.Log != nil {
666						_, _ = fmt.Fprintf(runtime.Log,
667							"triage gate error for %s: %v (skipping)\n", candidate.ID, triageErr)
668					}
669					emit("triage.error", map[string]any{
670						"bead_id": candidate.ID,
671						"reason":  triageErr.Error(),
672					})
673					// A gate error does not count as an attempt; re-pick next candidate.
674					continue
675				}
676				if !shouldClaim {
677					if runtime.Log != nil {
678						_, _ = fmt.Fprintf(runtime.Log,
679							"triage: skipped dispatch of %s (classified as non-atomic)\n", candidate.ID)
680					}
681					emit("triage.skipped", map[string]any{"bead_id": candidate.ID})
682					continue
683				}
684			}
685	
686			if err := w.Store.Claim(candidate.ID, assignee); err != nil {
687				// Another worker won the race for this bead. Emit a structured
688				// claim_race event so concurrent-worker losses are observable
689				// (ddx-9d55601f AC #4). The bead remains in `attempted` for this
690				// run; on the next iteration it will be filtered out of
691				// ReadyExecution naturally because Claim() flipped it to
692				// in_progress, so the loser keeps moving down priority order.
693				emit("picker.claim_race", map[string]any{
694					"bead_id":  candidate.ID,
695					"priority": candidate.Priority,
696					"reason":   err.Error(),
697				})
698				continue
699			}
700	
701			emit("bead.claimed", map[string]any{
702				"bead_id":  candidate.ID,
703				"title":    candidate.Title,
704				"assignee": assignee,
705			})
706	
707			if runtime.Log != nil {
708				if candidate.Title != "" {
709					_, _ = fmt.Fprintf(runtime.Log, "\n▶ %s: %s\n", candidate.ID, candidate.Title)
710				} else {
711					_, _ = fmt.Fprintf(runtime.Log, "\n▶ %s\n", candidate.ID)
712				}
713			}
714	
715			// Generate a provisional attempt_id for progress events.
716			// The real attempt_id is assigned inside ExecuteBead; we use this
717			// for queueing/running events and replace with the real one once known.
718			provAttemptID := time.Now().UTC().Format("20060102T150405") + "-" + randomProgressID()
719			runStart := now()
720			phaseSeq := 0
721			nextPhase := func(phase string, heartbeat bool) {
722				phaseSeq++
723				emitProgress(runtime.ProgressCh, newProgressEvent(
724					runtime.WorkerID, runtime.ProjectRoot, candidate.ID, provAttemptID,
725					harness, model, profile,
726					phase, phaseSeq, heartbeat, now().Sub(runStart).Milliseconds(),
727				))
728			}
729	
730			nextPhase("queueing", false)
731	
732			hbCtx, hbCancel := context.WithCancel(ctx)
733			var hbWG sync.WaitGroup
734			hbWG.Add(1)
735			go func(beadID string) {
736				defer hbWG.Done()
737				ticker := time.NewTicker(heartbeatInterval)
738				defer ticker.Stop()
739				for {
740					select {
741					case <-hbCtx.Done():
742						return
743					case <-ticker.C:
744						_ = w.Store.Heartbeat(beadID)
745					}
746				}
747			}(candidate.ID)
748	
749			nextPhase("running", false)
750	
751			report, err := w.Executor.Execute(ctx, candidate.ID)
752			hbCancel()
753			hbWG.Wait()
754			if err != nil {
755				report = ExecuteBeadReport{
756					BeadID: candidate.ID,
757					Status: ExecuteBeadStatusExecutionFailed,
758					Detail: err.Error(),
759				}
760			}
761			if report.BeadID == "" {
762				report.BeadID = candidate.ID
763			}
764			if report.Status == "" {
765				report.Status = ExecuteBeadStatusExecutionFailed
766			}
767			if report.Detail == "" {
768				report.Detail = ExecuteBeadStatusDetail(report.Status, "", "")
769			}

100				if running >= *wc.MaxCount {
101					return nil, fmt.Errorf("workers.max_count cap reached: %d running (limit %d)", running, *wc.MaxCount)
102				}
103			}
104		}
105	
106		// Default-path contract (ddx-755f5881 AC #1): an empty dispatch input
107		// (no rawArgs, no workers.default_spec) must produce a spec with
108		// Profile: "default" and nothing else. This eliminates the historical
109		// 19-burn drain-queue failure mode where an empty spec fanned out into
110		// per-tier ladder iteration with no upstream synthesis target.
111		if req.Profile == "" {
112			req.Profile = "default"
113		}
114	
115		// Default poll-interval = 30s for server-managed workers (ddx-dc157075).
116		// Operators wanting drain-and-exit semantics must pass --once or an
117		// explicit poll_interval=0 in the dispatch payload.
118		pollInterval := 30 * time.Second
119		if req.PollInterval != "" {
120			d, err := time.ParseDuration(req.PollInterval)
121			if err != nil {
122				return nil, fmt.Errorf("invalid poll_interval: %w", err)
123			}
124			pollInterval = d
125		}
126	
