2272		if p, ok := projectFromContext(r.Context()); ok {
2273			if m := s.workers.LandCoordinators.MetricsFor(p.Path); m != nil {
2274				writeJSON(w, http.StatusOK, []CoordinatorMetricsEntry{{
2275					ProjectRoot: p.Path,
2276					Metrics:     *m,
2277				}})
2278				return
2279			}
2280			writeJSON(w, http.StatusOK, []CoordinatorMetricsEntry{})
2281			return
2282		}
