2286	func (s *Server) handleStartExecuteLoopWorker(w http.ResponseWriter, r *http.Request) {
2287		if !isTrusted(r) {
2288			writeJSON(w, http.StatusForbidden, map[string]string{"error": "dispatch endpoints are localhost-only"})
2289			return
2290		}
2291		var req struct {
2292			ProjectRoot   string `json:"project_root"`
2293			Harness       string `json:"harness"`
2294			Model         string `json:"model"`
2295			Profile       string `json:"profile"`
2296			Provider      string `json:"provider"`
2297			ModelRef      string `json:"model_ref"`
2298			Effort        string `json:"effort"`
2299			LabelFilter   string `json:"label_filter"`

2300			Once          bool   `json:"once"`
2301			PollInterval  string `json:"poll_interval"`
2302			NoReview      bool   `json:"no_review"`
2303			ReviewHarness string `json:"review_harness"`
2304			ReviewModel   string `json:"review_model"`
2305		}
2306		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
2307			writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid request body"})
2308			return
2309		}
2310	
2311		// Resolve project_root: if provided, validate it against registered projects.
2312		// An empty project_root means "use the server's primary project" (default).
2313		projectRoot := req.ProjectRoot
2314		if projectRoot != "" {
2315			resolved := s.resolveRequestedProject(projectRoot)
2316			if resolved == "" {
2317				writeJSON(w, http.StatusUnprocessableEntity, map[string]string{
2318					"error": fmt.Sprintf("no registered project matches %q; ensure the server was started from or has registered that project root", projectRoot),
2319				})
2320				return
2321			}
2322			projectRoot = resolved
2323		}
2324	
2325		// Default poll-interval = 30s for server-managed workers (ddx-dc157075).
2326		// Operators wanting drain-and-exit semantics must pass --once or an
2327		// explicit poll_interval=0 in the dispatch payload.
2328		pollInterval := 30 * time.Second
2329		if strings.TrimSpace(req.PollInterval) != "" {
2330			d, err := time.ParseDuration(req.PollInterval)
2331			if err != nil {
2332				writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid poll_interval"})
2333				return
2334			}
2335			pollInterval = d
2336		}
2337		record, err := s.workers.StartExecuteLoop(ExecuteLoopWorkerSpec{
2338			ProjectRoot:   projectRoot,
2339			Harness:       req.Harness,
2340			Model:         req.Model,
2341			Profile:       req.Profile,
2342			Provider:      req.Provider,
2343			ModelRef:      req.ModelRef,
2344			Effort:        req.Effort,
2345			LabelFilter:   req.LabelFilter,
2346			Once:          req.Once,
2347			PollInterval:  pollInterval,
2348			NoReview:      req.NoReview,
2349			ReviewHarness: req.ReviewHarness,
2350			ReviewModel:   req.ReviewModel,
2351		})
2352		if err != nil {
2353			writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
2354			return
2355		}
2356		writeJSON(w, http.StatusCreated, record)
2357	}
