2359	// resolveRequestedProject matches a requested project_root string against
2360	// registered projects. It tries exact path match first, then name (basename)
2361	// match. Returns the canonical path on success, or "" if no match or ambiguous.
2362	func (s *Server) resolveRequestedProject(requested string) string {
2363		// Exact path match via the state's lookup method.
2364		if entry, ok := s.state.GetProjectByPath(requested); ok {
2365			return entry.Path
2366		}
2367		// Name (basename) match — only unambiguous if exactly one project has that name.
2368		projects := s.state.GetProjects()
2369		var matches []string
2370		for _, p := range projects {
2371			if p.Name == requested {
2372				matches = append(matches, p.Path)
2373			}
2374		}
2375		if len(matches) == 1 {
2376			return matches[0]
2377		}
2378		return ""
2379	}
